    "modules.dev_test_backend": "Backend - pytest",
    "modules.dev_test_e2e": "E2E - Playwright",
    "modules.dev_test_frontend": "Frontend - vitest",
    "modules.dev_test_intro": "Kiểm thử kiểm soát mọi PR. Dự án sử dụng pytest cho backend, vitest cho frontend, và Playwright cho e2e. Chạy locally cùng lệnh như trong CI.",
    "modules.dev_test_pattern": "Kiểm thử backend dùng httpx + ASGITransport, không có HTTP thực. Kiểm thử frontend chạy trong jsdom. Fixture tích hợp dùng chung nằm trong backend/tests/integration/_auth_helpers.py.",
    "modules.dev_test_title": "Kiểm thử module của bạn",
    "modules.dev_tree_backend": "Module backend",
    "modules.dev_tree_frontend": "Module frontend",
    "modules.dev_tree_intro": "Cả module backend và frontend đều tuân theo quy ước nghiêm ngặt. Tuân thủ và loader + registry sẽ kết nối mọi thứ; vi phạm và mọi thứ sẽ hỏng theo những cách bất ngờ.",
    "modules.dev_tree_note": "Tất cả file ngoại trừ manifest.* đều là tùy chọn, bắt đầu với tập hợp nhỏ nhất và thêm file khi module phát triển.",
    "modules.dev_tree_title": "Cấu trúc file, cái gì đặt ở đâu",
    "modules.dev_trouble_1_a": "Backend phải được khởi động lại sau khi đặt thư mục vào. Kiểm tra log khởi động để tìm \"[modules] loaded oe_your_module\". Không thấy? Xác minh __init__.py tồn tại và manifest.py định nghĩa object `manifest` ở phạm vi module.",
    "modules.dev_trouble_1_q": "Module không xuất hiện trong Modules & Marketplace",
    "modules.dev_trouble_2_a": "Loader thêm tiền tố /api/v1/<module_name>/. Vì vậy đường dẫn router.py như @router.get(\"/\") trở thành /api/v1/my_module/. Giữ dấu gạch chéo cuối trên API client frontend, redirect_slashes bị tắt trên backend.",
    "modules.dev_trouble_2_q": "Lỗi 404 trên các route",
    "modules.dev_trouble_3_a": "Alembic chỉ nhìn thấy các model được import khi khởi động ứng dụng. Thêm dòng \"from app.modules.my_module import models as _m  # noqa: F401\" trong _import_models_for_migrations (backend/app/main.py).",
    "modules.dev_trouble_3_q": "Alembic autogenerate tạo ra migration trống",
    "modules.dev_trouble_4_a": "Bạn quên thêm giá trị dự phòng tiếng Anh trong frontend/src/app/i18n-fallbacks.ts. Thêm vào đó, backend phục vụ locales qua /api/v1/i18n/ bằng cách hợp nhất file đó với mỗi JSON dịch thuật.",
    "modules.dev_trouble_4_q": "Frontend hiển thị khóa i18n thô như \"modules.my_feature.title\"",
    "modules.dev_trouble_5_a": "Bạn đã khai báo quyền mới nhưng không có vai trò nào có nó. Sửa backend/app/modules/users/seed_roles.py và chạy lại seed. Admin luôn bỏ qua; mọi vai trò khác cần cấp tường minh.",
    "modules.dev_trouble_5_q": "Lỗi 403 Thiếu quyền: my_module.create",
    "modules.dev_trouble_6_a": "Hợp đồng nằm trong frontend/src/modules/_types.ts, import ModuleManifest từ đó. Không bao giờ sửa _types.ts hoặc cấu trúc của _registry.ts: chỉ thêm import của bạn vào mảng MODULE_REGISTRY.",
    "modules.dev_trouble_6_q": "Lỗi TypeScript trong manifest.ts về routes",
    "modules.dev_trouble_7_a": "Kiểm tra defaultEnabled là true trong manifest.ts (người dùng vẫn có thể tắt sau qua trang Modules), và mục nav của item có group khớp với id group thanh bên hiện có. advancedOnly: true ẩn item cho đến khi người dùng bật \"Chế độ nâng cao\" từ Cài đặt.",
    "modules.dev_trouble_7_q": "Mục điều hướng không xuất hiện trong thanh bên",
    "modules.dev_trouble_title": "Khắc phục sự cố, các vấn đề thường gặp",
    "modules.dev_what": "Module là gì?",
    "modules.dev_what_backend": "Chỉ backend",
    "modules.dev_what_backend_ex": "ví dụ: connector API mới hoặc webhook receiver",
    "modules.dev_what_desc": "OpenConstructionERP v4.3 có hơn 110 module. Mọi tính năng nghiệp vụ, BOQ, BIM Hub, Tiến độ, CDE, gói BOQ khu vực, công cụ AI, đều là module độc lập. Module có thể thêm REST routes, bảng cơ sở dữ liệu, trang UI, quy tắc kiểm tra, bản dịch, hoặc bất kỳ kết hợp nào. Bạn có thể kích hoạt, vô hiệu hóa, cài đặt hoặc thay thế bất kỳ module nào mà không cần chạm vào core.",
    "modules.dev_what_frontend": "Chỉ frontend",
    "modules.dev_what_frontend_ex": "ví dụ: giao diện trao đổi BOQ khu vực hoặc báo cáo chuyên biệt",
